import{_ as a,o as t,c as T,j as r,a as b,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"3.ST守则与ST开团指南","description":"","frontmatter":{},"headers":[],"relativePath":"6.STG/3.ST守则与ST开团指南.md","filePath":"6.STG/3.ST守则与ST开团指南.md"}'),S={name:"6.STG/3.ST守则与ST开团指南.md"};function p(n,e,o,_,d,l){return t(),T("div",null,[...e[0]||(e[0]=[r("h1",{id:"_3-st守则与st开团指南",tabindex:"-1"},[b("3.ST守则与ST开团指南 "),r("a",{class:"header-anchor",href:"#_3-st守则与st开团指南","aria-label":'Permalink to "3.ST守则与ST开团指南"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001A")])])],-1),s('<h1 id="st守则与st开团指南" tabindex="-1">ST守则与ST开团指南 <a class="header-anchor" href="#st守则与st开团指南" aria-label="Permalink to &quot;ST守则与ST开团指南&quot;">​</a></h1><p>本文出于对新手ST的指引和教学而作，主要目的是令更多新手ST快速了解本书，同时也规范出ST的守则，鼓励更多新手ST成为遵守游戏逻辑与规则的人。——魔术师 留</p><p><strong>ST守则：</strong><br> 1.公平的对待每一个玩家，也有拒绝某个玩家的权利。<br> 2.开团的目的是讲好一个故事，规则可以为故事让步。<br> 3.尽可能的照顾每一种被玩家购买的强化，至少让它们有用。<br> 4.尽可能的让每个人都沉浸在故事中。<br> 5.避免无聊冗长的剧情，避免机械降神（deus ex machina），也尽可能不要设置开门杀、机制杀。<br> 6.对玩家适当引导，降低控制欲。<br> 7.尽可能不要设计过多的，无休止的战斗，这会让游戏变得相当乏味。<br> 8.鼓励玩家扮演的同时，自己也应试着沉浸扮演。<br> 9.尽量不要以上帝视角对待玩家的选择，大部分时刻都是当局者迷的。</p><p><em>**ST开团指南<br> **</em><br> **写在最前面的：ST作为游戏的主持人，拥有让规则让步的权利，但最好是为剧情需要，而不是意味着ST可以不看规则书或灌输错误的规则解读。<br> **<br> 接下来，将简单阐述在TMD模式下的理论基础。</p><p></p><p>①一个标准<br> 一个标准，顾名思义，就是对于同等级同水平人物卡时使用统一标准，随着人物卡等级上升，这个标准也应逐渐调整，但要注意的是，高等级人物卡应得到应有的影片内地位，而不是从一开始的木棒打龙虾变成后面的碎船大棒打虾薪王，或者路边随便一条野狗就能咬死A人或者S人。简而言之，在某世界观框架下，制定一个随人物卡等级变动的标准是很重要的，但不应出现所有方面都随之变强的情况，可以随之升级的有：关键战斗难度，检定DC等（如白卡的检定难度应为简单1中等2困难3，随着等级的上升进行调整）。但与此同时，也要对具体情况具体对待，如：有某位轮回者比其他轮回者要更强，或有某位轮回者比其他轮回者要更弱，则ST应将战斗分开，或鼓励团队协作，采用1+1＞2的形式设计战斗。</p><p>②一个原则<br> 本着健康、快乐游戏的原则，ST应该兼顾战力和和画风在影片中的均衡，尽可能的让玩家愉快的演绎故事。而要做到这一点，一般秉承的是“故事的推进不能没有玩家，故事的演绎需要玩家”的基本原则，在一场影片中讲述他人的故事或者NPC的故事是很令人失望的，这几乎无法突显出轮回者的作用，也不会让他们认为是自己在演绎故事，缺乏传奇感，缺乏主角观。而另一点相当重要的事是，尽可能的避免对电波的情况，让玩家真正理解你究竟在说什么，尽可能避免让玩家无事可做，如同没头苍蝇一样乱转，或是到哪都无法收集线索，这是相当难以下咽的。</p><p>**引申——传奇感<br> **何为传奇感？可以通俗简单的理解为“具有令人激动的剧情、跌宕起伏，一波三折的故事结构、更强的演绎性”，具有传奇感的剧情是玩家所需要的，是能带来更好的演绎效果的，ST无需吝啬笔墨，让玩家真正沉浸的体验到“传奇”概念，并试图真正的成为它。</p><p>**引申——主角观<br> **在三面墙之内，戏剧性的张力离不开主角，观众们追随主角的视角一窥世界的全貌。在一出精心结构的戏里，诙谐的部分使主角娱乐，严肃的部分给他教益，剧情的发展使他惊奇，穿插的情节添他的智慧，诡计长他的见识，鉴戒促他醒悟，罪恶激动他的义愤，美德引起他的羡慕。成为主角，成为被注视者，以故事的演绎者的姿态应对，这是至关重要的。</p><p>③一些调整<br> 根据轮回者强度对剧本结构进行适当调整是很有必要的。在轮回者强度评级的基础上，以「唯结果论」决定后续内容，轮回者评级的部分决定了剧本的整体难度，而唯结果论则决定了解决方案，ST应尝试处理评级不同和评级相同两种情况<br> 在一些情况下，可以为较弱的轮回者安排剧本内增益以追赶差距，在剧本结束后收回，避免陷入因弱势而无法适应影片，因此无法获得更多的资源，因此无法追赶差距的恶性循环。<br> 在另一些情况下，分线探索，搏得更高的上限也不失为一种好的解决方案，将强弱不等的轮回者分开，分别设置难度，让每个人都有其足以适应的强度环境。<br> 切记，不要以“<strong><em>我没有撕你的卡啊</em></strong>。”作为借口和理由，让玩家必须对抗他无法对抗的敌人。ST也无需将影片中的每个敌人都设置到玩家可以击败的程度，可以根据强化路线准备惩罚怪。<br> 在影片结束时，发放资源也会跟着影片内结果进行调整，一般而言，影片结束时，会根据影片表现、人物作用、故事完整度发放奖励，故事完整度决定基础奖励+购点分数（即只能用于购买属性、技能、专业的分数），影片表现决定表现分，人物作用会发放额外的经验数。<br> 同时，影片的幕间设计在TMD模式下也有更好的解决方式。将一个长的、连贯的影片根据重要的时间节点进行拆分，每到达一个时间节点便视为结束了一次，所有影片成长在此时成长，但轮回者们并没有离开这个影片，所以他们无法花费分数兑换和购买，但可以花费经验升级属性、技能、专业、学习技艺等，因此，ST可以酌情发放一些经验用于补强以适应接下来的剧情。</p><p>**延伸阅读——战斗设计<br> **●怪物设计<br> 千里之行，始于怪物设计。怪物的设计是战斗的核心，也是战斗的主要构成要素之一。一般而言，怪物应按「轮回者基数」来规划强度，无需按照白卡中规中矩的车一张怪，而是确定一个固定的战斗方式、固定的攻击、防御数值，利用特性数引入机制，再通过对怪物的定位决定难度。一般而言，考虑到小队整体水平，Boss的难度等级应该在总计后1.5-2倍水平，精英的难度等级平均下降一级，小怪无需严格计算，可以以怪物小队的形式派出，强调战术合作。<br> 如何按「轮回者基数」来规划强度？以唯结果论的基础，根据轮回者强度评级和团队人数进行评定，每有一个符合ST预期的轮回者，就根据等级增加D1C2B4A8S10个「轮回者基数」。一个「轮回者基数」增加同级一单位资源量（可拆分），也可以兑换成同级两特性（详见撰写规则）；如果某轮回者不符合ST预期，则参考上述调整方式，或直接不增加「轮回者基数」。<br> 当我们在讨论怪物机制时我们在讨论什么？什么是好的机制，什么是恶性机制？<br> 恶性机制，一般指会为电波系破局方式的机制，ST不可能也不应该幻想每个玩家都能理解所谓的破局方式，从一开始就被埋藏很深的某个答案在玩家的视角可能在整场影片结束都未曾知晓，而没有掌握这种破局方式就等同于团灭无异于是一种相当无聊的设计方案。多种解决方案，多种玩法，能刺激玩家的想象力和思考的战斗方式是我所推崇的。<br> 什么是好的机制？ST不仅有开团的义务，也有让玩家学会健康游戏的义务，这样才能让玩家以正常的人物卡正常的跑团，反哺影片的流畅，对于设计瘸腿的轮回者设计惩罚怪可以促进车卡的全方位发展，引入战术和团队协作也可以有效的让他们理解跑团的魅力。</p><p>●战斗流程<br> 战斗流程是指对整场影片的战斗总览设计，也包括每场战斗的细枝末节。接下来将分两个层面叙述基础理念：<br> ①总览：<br> “推进剧情不是为了战斗，恰恰相反，战斗是为了推进剧情。”<br> 乏味冗长，连续不断的战斗并不会带来无双割草的感觉，只会让人觉得ST没活了。数量恰到好处、难度恰到好处的剧本才会带来更好的体验，以白卡举例，白卡团遵循“一次战斗、一次挑战”的原则，可以有效的让玩家既体验到战斗的乐趣，又不至于感觉到无聊，而设置的挑战能激发他们的探索欲和思考。<br> 而面对更加具有传奇感的场面时（如：军团作战），ST可直接简化战斗步骤，甚至完全不设计战斗，以玩家的RP为准，给予足够的正反馈，让玩家乐于扮演，乐于推动剧情，就足够了。<br> ②细枝末节<br> 而从细枝末节上来讲，如何分配怪物的仇恨度、如何运用设计好的机制，如何采取有效的战斗方式是很重要的。<br> 单个怪物的仇恨度有两种判定方式，一种是结合剧情，是否有剧情中的首要攻击目标，若无，则跳至下一项；另一种是目前哪位轮回者对这只怪物造成的伤害最高，若其能被怪物攻击到，则优先攻击之，否则，顺位下延，若怪物最先行动，则随机选取。<br> 集群怪物若有战术，则按预定的战术计划行动，其基础行为逻辑由战术决定。</p><p>●战术<br> 战术是基于思考逻辑的具象化表现，运用战术对抗玩家的团队协作，让战斗更富有趣味。战术意味着ST要用玩家的思考方式进行思考，而不是纯粹的随机游戏方式。但无论如何，使用战术时不应以上帝视角审视玩家小队，简单而言，即不要“开天眼”，但这并不意味着不能采取迅速减员或者针对最强战力的战术，相反，这也是合理的。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const h=a(S,[["render",p]]);export{c as __pageData,h as default};
